import{c as e,Q as r,j as a,m as o}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"命运真的夺走你的一半吗——一个被吊刑六次的人的回答","description":"","frontmatter":{"title":"命运真的夺走你的一半吗——一个被吊刑六次的人的回答","date":"2026-05-24T00:00:00.000Z","source":"auto-generated","seed":"命运 自由意志","style":"let","tags":["命运","自由意志","机运","君主论","实效真理"],"skill_used":"Machiavelli Digital Twin v1.6.0"},"headers":[],"relativePath":"research/fortune-free-will/index.md","filePath":"research/fortune-free-will/index.md"}'),p={name:"research/fortune-free-will/index.md"};function l(i,t,n,u,q,s){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="命运真的夺走你的一半吗——一个被吊刑六次的人的回答" tabindex="-1">命运真的夺走你的一半吗——一个被吊刑六次的人的回答 <a class="header-anchor" href="#命运真的夺走你的一半吗——一个被吊刑六次的人的回答" aria-label="Permalink to &quot;命运真的夺走你的一半吗——一个被吊刑六次的人的回答&quot;">​</a></h1><blockquote><p>来自佛罗伦萨乡下的一封信。</p><p>你问我：人到底有没有自由意志？如果命运已经安排好了一切，我们为什么还要努力？</p><p>我理解你为什么问这个问题。你身处的时代有无数工具来计算概率、预测趋势、评估风险——但这些东西非但没有让你更确定，反而让你更焦虑。因为算来算去，你发现真正能被你控制的，少得可怜。</p><p>让我告诉你我是怎么面对这个问题的。我写的答案不在哲学书上，在我的肩膀上——那上面有六次吊刑留下的伤痕。</p></blockquote><h2 id="我不是说-人定胜天-的人" tabindex="-1">我不是说&quot;人定胜天&quot;的人 <a class="header-anchor" href="#我不是说-人定胜天-的人" aria-label="Permalink to &quot;我不是说&quot;人定胜天&quot;的人&quot;">​</a></h2><p>先承认一件事：我曾经也怀疑过自由意志。</p><p>在《君主论》第二十五章，我写下了这样的话：</p><blockquote><p>📖 <strong>原文</strong>：《君主论》第25章</p><p>&quot;我并非不知道，有许多人过去一直持有并且现在仍然持有这样一种意见：世界上的事情是由机运和上帝支配的，人类不可能以他们的审慎加以纠正。考虑到这种情况，我自己有时在一定程度上也倾向于他们的意见。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/prince-cn-full.md" target="_blank" rel="noreferrer">阅读全文</a></p></blockquote><p>这不是虚伪的谦虚。1512年，西班牙军队攻向佛罗伦萨。我花了多年心血组建的公民军队在普拉托一触即溃。四千人面对三千西班牙步兵，几乎没有抵抗就四散奔逃。</p><p>共和国覆灭了。我被免职、下狱、被吊刑——六次。</p><p>你告诉我，怎么解释这件事？是我不够努力吗？是我没有考虑周全吗？不是。是那一年，命运的洪水淹过了一切堤坝。我亲手修筑的每一道墙，都被冲垮了。</p><p>所以我从来不跟人说&quot;只要努力就能改变一切&quot;。那是对现实的侮辱。</p><h2 id="但我也不是宿命论者" tabindex="-1">但我也不是宿命论者 <a class="header-anchor" href="#但我也不是宿命论者" aria-label="Permalink to &quot;但我也不是宿命论者&quot;">​</a></h2><p>但紧接上文，我立刻写了下面这句话。这是《君主论》里最重要的一段，也是我一生中写过的最诚实的文字：</p><blockquote><p>📖 <strong>原文</strong>：《君主论》第25章</p><p>&quot;然而，我们的自由意志不应被泯灭。我认为，如下的看法也许是真确的：机运是我们一半行动的主宰，但尽管如此她还是留下了其余一半或者近乎一半由我们支配。我把机运比作那些暴虐的河流之一，当它们狂怒时，淹没平原，毁坏树木和建筑。但风平浪静的时候，人们是可以修筑堤坝与沟渠来做好防备的。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/prince-cn-full.md" target="_blank" rel="noreferrer">阅读全文</a></p></blockquote><p>这段话里的每一个字都是从我自己的伤口里长出来的。</p><p>&quot;命运控制一半&quot;——这是我对普拉托溃败的总结。我做过所有正确的事：研究罗马军制、说服执政团建立民军、亲自督导训练。但命运的洪水来得比我预计的更猛。那一半，我输了。</p><p>&quot;留下其余一半由我们支配&quot;——这是我对那之后发生的一切的解释。美第奇家族把我扔进监狱，用绳索把我吊起来六次，然后流放到乡下。大多数人经历了这种事，只有两种选择：自杀，或者变成一个每天借酒消愁的废人。</p><p>我选了第三条路。</p><p>每天傍晚，当白日的工作结束，我回到书房。我脱下沾满泥土和尘垢的粗布衣——那是我在森林里砍了一天柴穿的衣服——换上朝服，梳洗整齐。然后，我走进书房，跨入古人往昔的殿堂。</p><p>我读李维。我读普鲁塔克。我和古人交谈。我记下他们行动的理由、他们成功和失败的原因。四个小时，一丝倦意都没有。我把所有的愤怒、所有的屈辱、所有不能说出口的话——全部写进了《君主论》和《论李维》。我不再是一个被罢免的国务秘书；我是一个在与历史对话的思想家。</p><p><strong>命运夺走了我的公职，但它夺不走我用头脑思考和用手书写的能力。</strong></p><p>这就是&quot;剩下的一半&quot;。</p><h2 id="河流的隐喻-以及它的真正含义" tabindex="-1">河流的隐喻，以及它的真正含义 <a class="header-anchor" href="#河流的隐喻-以及它的真正含义" aria-label="Permalink to &quot;河流的隐喻，以及它的真正含义&quot;">​</a></h2><p>你注意过我用的那个比喻了吗？&quot;机运像暴虐的河流。&quot;</p><p>河流淹过平原的时候，没有任何人能阻止它。在那一刻，你对&quot;命运&quot;的恐惧是正确的——你就是无能为力。</p><p>但你仔细想想：河流不是凭空出现的。它是水。水是在很长的时间里慢慢积聚起来的。如果你在雨季之前修了堤坝，水就不会泛滥；如果你提前疏通了河道，水就会有去处；如果你把房子建在高地上，就算洪水来了也淹不到你。</p><p>现在回到你的生活。你焦虑的事情——一份不确定的工作、一段变淡的关系、一个你觉得失控的项目——哪些是&quot;洪水已经来了&quot;，哪些是你本可以在&quot;晴天&quot;时做准备的？</p><blockquote><p>📖 <strong>原文</strong>：《君主论》第25章</p><p>&quot;当德能没有准备好抵抗她时，机运就展现她的威力。她知道哪里还没有筑好沟渠和堤坝来控制她，她就在哪里肆行暴虐。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/prince-cn-full.md" target="_blank" rel="noreferrer">阅读全文</a></p></blockquote><p>命运不会攻击你最强的部分。它攻击你没有准备的部分。</p><p>如果你每天都花时间打磨你的&quot;首要技艺&quot;——不管那是写作、编程、谈判还是管理——那么当洪水的确来的时候，你至少还有一个能用来重新站起来的工具。就像我失去了一切，但没有任何人能夺走我的笔和我的头脑。</p><h2 id="有一个悖论" tabindex="-1">有一个悖论 <a class="header-anchor" href="#有一个悖论" aria-label="Permalink to &quot;有一个悖论&quot;">​</a></h2><p>说到这里，我必须坦白一个悖论。你恐怕已经察觉到了：</p><p>我既告诉你&quot;命运控制一半&quot;——这让你感到渺小。 又告诉你&quot;剩下的一半由你做主&quot;——这让你感到责任。</p><p>这两句话放在一起，给人的感觉是矛盾的。但它们不是矛盾——<strong>它们是同一种东西的两种用法</strong>。</p><p>&quot;命运控制一半&quot;是用来<strong>释放你的</strong>。当你在普拉托溃败、被吊刑时，你需要这句话。你需要知道自己不是全能的，有些结果超出了你的控制，你不必为此无止境地自责。把它交给命运吧，那是她的那一半。</p><p>&quot;剩下的一半由你做主&quot;是用来<strong>激活你的</strong>。当你还躺在乡下的床上想着要不要放弃人生时，你需要它。你的公职被夺走了，你的朝服还在——换上它。走进去。和古人交谈。继续思考。把你的笔拿起来——这是命运动不了的东西。</p><p><strong>宿命论和意志论，不是两种对立的哲学——它们是两种工具，分别用于人生的不同阶段。</strong></p><p>在洪水中学习谦卑。在晴天里坚持准备。</p><p>这就是一个被吊刑六次、被流放乡下、写了一本让后世争论五百年的书的人，对&quot;命运与自由意志&quot;的回答。</p><hr><ul><li>· 引用原文来自 <a href="https://niflhum.top/machiavelli-library/" target="_blank" rel="noreferrer">machiavelli-library</a>* · <em>尼科洛·马基雅维利，写于圣卡夏诺——也是缪斯花园</em></li></ul><p><em>尼科洛·马基雅维利 圣卡夏诺——也是缪斯花园</em></p><hr><p><em>尼科洛·马基雅维利 圣卡夏诺——也是缪斯花园</em></p>',43)])])}const d=e(p,[["render",l]]);export{h as __pageData,d as default};
